# Basic auth
client = httpx.AsyncClient(auth=("user", "password"))

# Bearer token
class BearerAuth(httpx.Auth):
    def __init__(self, token: str):
        self.token = token
    def auth_flow(self, request):
        request.headers["Authorization"] = f"Bearer {self.token}"
        yield request

client = httpx.AsyncClient(auth=BearerAuth("my-token"))

# OAuth2 with token refresh (custom auth flow with two requests)
class RefreshingAuth(httpx.Auth):
    requires_response_body = True
    def auth_flow(self, request):
        request.headers["Authorization"] = f"Bearer {self.access_token}"
        response = yield request
        if response.status_code == 401:
            self.refresh()
            request.headers["Authorization"] = f"Bearer {self.access_token}"
            yield request

def log_request(request: httpx.Request):
    print(f"→ {request.method} {request.url}")

def log_response(response: httpx.Response):
    print(f"← {response.status_code} in {response.elapsed.total_seconds():.2f}s")

async with httpx.AsyncClient(
    event_hooks={"request": [log_request], "response": [log_response]}
) as client:
    await client.get("https://httpbin.org/get")

import asyncio
import httpx
from typing import Any

PROVIDERS = [
    {
        "url": "https://api.openai.com/v1/chat/completions",
        "headers": {"Authorization": f"Bearer {OPENAI_KEY}"},
        "body": lambda prompt: {
            "model": "gpt-4o", "messages": [{"role": "user", "content": prompt}]
        },
    },
    {
        "url": "https://api.anthropic.com/v1/messages",
        "headers": {
            "x-api-key": ANTHROPIC_KEY,
            "anthropic-version": "2023-06-01",
        },
        "body": lambda prompt: {
            "model": "claude-opus-4-6",
            "max_tokens": 1024,
            "messages": [{"role": "user", "content": prompt}],
        },
    },
]

async def call_provider(
    client: httpx.AsyncClient,
    provider: dict,
    prompt: str,
) -> dict[str, Any]:
    response = await client.post(
        provider["url"],
        headers=provider["headers"],
        json=provider["body"](prompt),
        timeout=httpx.Timeout(connect=5.0, read=60.0, write=5.0, pool=5.0),
    )
    response.raise_for_status()
    return response.json()

async def race_llms(prompt: str) -> dict[str, Any]:
    """Call all providers concurrently; return the first success."""
    async with httpx.AsyncClient(http2=True) as client:
        tasks = [
            asyncio.create_task(call_provider(client, p, prompt))
            for p in PROVIDERS
        ]
        done, pending = await asyncio.wait(tasks, return_when=asyncio.FIRST_COMPLETED)
        for task in pending:
            task.cancel()
        return done.pop().result()

from tenacity import retry, stop_after_attempt, wait_exponential, retry_if_exception_type

@retry(
    retry=retry_if_exception_type((httpx.HTTPStatusError, httpx.TimeoutException)),
    wait=wait_exponential(multiplier=1, min=1, max=10),
    stop=stop_after_attempt(4),
)
async def resilient_fetch(client: httpx.AsyncClient, url: str) -> dict:
    response = await client.get(url)
    response.raise_for_status()
    return response.json()

import httpx

def handler(request: httpx.Request) -> httpx.Response:
    return httpx.Response(200, json={"status": "ok"})

transport = httpx.MockTransport(handler=handler)
client = httpx.AsyncClient(transport=transport)

from urllib.parse import urlparse

ALLOWED_HOSTS = {"api.openai.com", "api.anthropic.com"}

def validate_url(url: str) -> None:
    parsed = urlparse(url)
    if parsed.hostname not in ALLOWED_HOSTS:
        raise ValueError(f"Disallowed host: {parsed.hostname}")
